{{
  "Total Received:  " +
  fmt.currency(
    (tblQuoFinDeposits.updatedRows || []).length
      ? (getEventDeposits.data || []).map(row => {
          const edit = (tblQuoFinDeposits.updatedRows || [])
            .find(x => x.allFields?.deposit_id === row.deposit_id);

          return edit
            ? { ...row, ...edit.allFields, ...edit.updatedFields }
            : row;
        }).reduce(
          (sum, row) => sum + Number(row.amount_received || 0),
          0
        )
      : (getEventDeposits.data || []).reduce(
          (sum, row) => sum + Number(row.amount_received || 0),
          0
        )
  )
}}
